INSERT INTO `activity` VALUES (1, '社区春季运动会', '欢迎大家参加社区春季运动会！活动包括跑步、跳绳、拔河等项目，还有精美礼品等着您！', '2024-05-01 09:00:00', '小区广场', 1, 45, 100, '/profile/upload/2026/04/17/b_8726adb7d6e655d7c8b2de14e5aee462_20260417155327A001.jpg', NULL, '2026-04-17 15:40:58', NULL, '2026-04-17 15:53:29', 0);
INSERT INTO `activity` VALUES (2, '亲子手工DIY活动', '亲子手工DIY活动，增进亲子关系，培养孩子的动手能力。材料由社区提供，欢迎报名参加！', '2024-04-20 14:00:00', '社区活动中心', 0, 20, 30, NULL, NULL, '2026-04-17 15:40:58', NULL, '2026-04-17 15:40:58', 0);
INSERT INTO `activity` VALUES (3, '健康义诊活动', '社区联合医院开展健康义诊活动，免费为居民测量血压、血糖，提供健康咨询服务。', '2024-04-15 09:00:00', '物业服务中心', 2, 80, 80, NULL, NULL, '2026-04-17 15:40:58', NULL, '2026-04-17 15:40:58', 0);
INSERT INTO `activity` VALUES (4, '端午节包粽子比赛', '端午节即将到来，社区举办包粽子比赛，获胜者有精美礼品！', '2024-06-10 10:00:00', '社区食堂', 0, 15, 50, NULL, NULL, '2026-04-17 15:40:58', NULL, '2026-04-17 15:40:58', 0);
INSERT INTO `activity` VALUES (5, '夏日纳凉电影节', '夏夜露天电影，带上家人一起来享受美好时光！', '2024-07-15 19:00:00', '小区广场', 0, 0, 200, NULL, NULL, '2026-04-17 15:40:58', NULL, '2026-04-17 15:40:58', 0);
