INSERT INTO `sys_oper_log` VALUES (108, '创建表', 0, 'com.ruoyi.generator.controller.GenController.createTableSave()', 'POST', 1, 'wyx', '研发部门', '/tool/gen/createTable', '127.0.0.1', '内网IP', '{\"sql\":\"-- 运动团队主表\\nCREATE TABLE `sport_team` (\\n  `id`            bigint unsigned NOT NULL AUTO_INCREMENT COMMENT \'主键\',\\n  `avatar`        varchar(255)    NOT NULL DEFAULT \'\' COMMENT \'团队头像URL（正方形）\',\\n  `team_name`     varchar(60)     NOT NULL DEFAULT \'\' COMMENT \'团队名称\',\\n  `member_count`  int unsigned    NOT NULL DEFAULT 0 COMMENT \'团队人数\',\\n  `category`      enum(\'跑步\',\'健走\',\'跑走\',\'骑行\',\'健身\') \\n                  NOT NULL COMMENT \'团队分类\',\\n  `is_deleted`    tinyint(1)      NOT NULL DEFAULT 0 COMMENT \'软删除：0正常 1已删除\',\\n  `created_at`    datetime        NOT NULL DEFAULT CURRENT_TIMESTAMP,\\n  `updated_at`    datetime        NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\\n  PRIMARY KEY (`id`),\\n  KEY `idx_category` (`category`)      -- 按分类筛选\\n) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT=\'运动团队列表\';\"}', '{\"msg\":\"创建表结构异常\",\"code\":500}', 0, NULL, '2026-01-05 14:18:33', 4);
