INSERT INTO `sys_oper_log` VALUES (1029, '通知公告', 2, 'com.ruoyi.web.controller.system.SysNoticeController.edit()', 'PUT', 1, 'wyx', '后端开发工程师', '/system/notice', '127.0.0.1', '内网IP', '{\"createBy\":\"wyx\",\"createTime\":\"2026-04-16 17:20:06\",\"noticeContent\":\"<p>关于加强小区消防安全、严防火灾事故的公告</p><p>各位业主/住户：</p><p>为切实保障小区全体业主/住户的生命财产安全，筑牢小区消防安全防线，有效防范各类火灾事故发生，结合近期消防安全工作要求，现将有关防火注意事项公告如下，请各位业主/住户严格遵守、共同落实：</p><p>一、强化居家防火意识，规范用电用气。居家期间请正确使用电器设备，不私拉乱接电线、不超负荷用电，离开家时务必关闭电灯、空调、热水器等所有电器电源；使用燃气热水器、燃气灶时，需保持通风良好，使用完毕后及时关闭燃气阀门，定期检查燃气管道、阀门及软管是否存在泄漏情况，发现问题立即联系物业或专业人员维修。</p><p>二、严禁违规存放易燃易爆物品。严禁在住宅内、楼道、楼梯间、消防通道、地下室等区域存放汽油、酒精、鞭炮、液化气罐等易燃易爆危险品，不携带易燃易爆物品进入小区公共区域，不私自储存大量易燃可燃杂物。</p><p>三、规范停放车辆，保障消防通道畅通。请将车辆有序停放在指定车位，严禁占用、堵塞消防通道、安全出口，严禁在消防栓、灭火器周边堆放杂物，确保消防设施完好有效、随时可用。</p><p>四、谨慎使用明火，杜绝火灾隐患。严禁在小区内露天焚烧垃圾、杂物，严禁在楼道内吸烟、乱扔烟头；居家祭祀、点香等使用明火时，需远离窗帘、被褥、纸箱等易燃物品，无人看管时不得遗留明火。</p><p>五、爱护消防设施，掌握应急技能。小区内的消防栓、灭火器、应急照明、疏散指示标志等消防设施，是火灾应急救援的重要保障，请勿随意损坏、挪用、遮挡；请各位业主/住户熟悉自家周边的疏散通道和安全出口，掌握基本的火灾逃生技巧，家中可配备灭火器、应急手电筒等消防器材，以备不时之需。</p><p>六、及时上报隐患，共筑安全防线。如发现小区内存在消防安全隐患（如违规用电用气、堵塞消防通道、消防设施损坏等），请及时拨打小区物业24小时值班电话或向物业工作人员反馈，以便及时整改消除隐患。</p><p>火灾无小事，防患于未然。消防安全关乎每一个家庭的幸福，离不开每一位业主/住户的共同努力。恳请各位业主/住户提高警惕、重视防火，自觉遵守本公告要求，主动排查自家火灾隐患，积极配合物业做好小区消防安全管理工作，共同营造安全、和谐、有序的居住环境。</p><p>特此公告。</p><p>wyx物业服务中心</p><p>1145.1.4</p>\",\"noticeId\":10,\"noticeTitle\":\"关于加强小区消防安全、严防火灾事故的公告\",\"noticeType\":\"2\",\"params\":{},\"status\":\"0\",\"updateBy\":\"wyx\",\"updateTime\":\"2026-04-16 17:23:50\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-04-16 19:08:54', 137);
