CREATE TABLE `running_routes`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `route_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '路线名称',
  `route_img` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '路线图片URL',
  `distance_km` decimal(10, 2) NOT NULL COMMENT '公里数，带2位小数',
