  `start_dist_km` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '起点距您公里数',
  `category` enum('公园路线','街道路线') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '路线分类',
  `exact_starting_address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_category`(`category` ASC) USING BTREE,
  INDEX `idx_start_dist`(`start_dist_km` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 8 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '跑步路线列表' ROW_FORMAT = Dynamic;

