-- ----------------------------
-- Table structure for stress
-- ----------------------------
DROP TABLE IF EXISTS `stress`;
CREATE TABLE `stress`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `datetime` datetime NULL DEFAULT NULL COMMENT '时间',
  `value` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '值',
  `userid` int(11) NULL DEFAULT NULL COMMENT '用户id',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = MyISAM AUTO_INCREMENT = 42 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '压力表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of stress
