-- ----------------------------
-- Table structure for workout_log
-- ----------------------------
DROP TABLE IF EXISTS `workout_log`;
CREATE TABLE `workout_log`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `workout_time` datetime NOT NULL COMMENT '运动开始时间（HH:MM:SS）',
  `category` enum('室内跑步','户外跑步','健走','户外骑行','泳池游泳','自由活动') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '运动分类',
  `calories` decimal(6, 2) NOT NULL COMMENT '消耗卡路里（千卡，可小数）',
  `duration` time NOT NULL COMMENT '运动时长（MM:SS 或 HH:MM:SS）',
  `userid` int(11) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_time`(`workout_time` ASC) USING BTREE,
  INDEX `idx_category`(`category` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '运动记录表' ROW_FORMAT = Dynamic;

