-- ----------------------------
-- Event structure for del_expired_captcha
-- ----------------------------
DROP EVENT IF EXISTS `del_expired_captcha`;
delimiter ;;
CREATE EVENT `del_expired_captcha`
ON SCHEDULE
EVERY '1' DAY STARTS '2026-01-06 03:00:00'
DO DELETE FROM `captcha` WHERE `expire_at` < NOW()
;;
delimiter ;

SET FOREIGN_KEY_CHECKS = 1;
